plugin.detectCode:
if (!input) return 0;
const hasTrailing = /[ \t]+$/m.test(input);
const hasDouble   = / {2,}/.test(input);
const hasCRLF     = /\r\n/.test(input);
return (hasTrailing || hasDouble || hasCRLF) ? 0.92 : 0.1;

plugin.executeCode:
const original = input;
// Normalize CRLF and CR to LF
let out = input.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
// Collapse multiple spaces/tabs within lines (preserve indentation intent)
out = out.split('\n').map(line => {
  // Strip trailing whitespace
  line = line.replace(/[ \t]+$/, '');
  // Collapse multiple spaces to single (not at line start)
  line = line.replace(/(?<=\S) {2,}/g, ' ');
  return line;
}).join('\n');
// Collapse more than 2 consecutive blank lines to 2
out = out.replace(/\n{3,}/g, '\n\n');
// Ensure single trailing newline
out = out.trimEnd() + '\n';
const origLines = original.split(/\r?\n/).length;
const newLines  = out.split('\n').length;
const summary = `// Whitespace normalized: ${origLines} → ${newLines} lines\n// CRLF→LF, trailing spaces removed, multiple spaces collapsed\n\n`;
return { output: out, outputLanguage: 'text' };
